const CPSPolly = React.forwardRef(function CPSPollyInner({ initialProject, initialPhases, onChangeProject, onChangePhases, onShareUrl }, fwdRef) {
  const _fitMobile = typeof window !== "undefined" && window.innerWidth < 640;
  const [project, setProjectRaw] = useState(() => initialProject || {
    name: "[Project Name]", client: "[Client Name]", startDate: "[Start Date]", deliveryDate: "[Delivery Date]", producer: "[Producer]"
  });
  const [phases, setPhasesRaw] = useState(() => initialPhases || cpsDefaultPhases());
  const [showAddPhase, setShowAddPhase] = useState(false);
  const [tab, setTab] = useState("timeline");
  const [printTabs, setPrintTabs] = useState(null); // null=normal, Set of tabs to force-render
  const printRef = useRef(null);

  /* Undo system */
  const historyRef = useRef([]);
  const MAX_HISTORY = 50;

  const pushHistory = () => {
    historyRef.current.push({ project: JSON.parse(JSON.stringify(project)), phases: JSON.parse(JSON.stringify(phases)) });
    if (historyRef.current.length > MAX_HISTORY) historyRef.current.shift();
  };

  const undo = () => {
    if (historyRef.current.length === 0) return;
    const prev = historyRef.current.pop();
    setProjectRaw(prev.project);
    setPhasesRaw(prev.phases);
  };

  const setProject = (updater) => {
    pushHistory();
    setProjectRaw(prev => {
      const next = typeof updater === 'function' ? updater(prev) : updater;
      if (onChangeProject) onChangeProject(next);
      return next;
    });
  };
  const setPhases = (updater) => {
    pushHistory();
    setPhasesRaw(prev => {
      const next = typeof updater === 'function' ? updater(prev) : updater;
      if (onChangePhases) onChangePhases(next);
      return next;
    });
  };

  /* Cmd+Z / Ctrl+Z listener */
  useEffect(() => {
    const handler = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === "z" && !e.shiftKey) {
        e.preventDefault();
        undo();
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  });

  const updateTask = (pi, ti, key, val) => {
    setPhases(prev => prev.map((p, i) => i === pi ? { ...p, tasks: p.tasks.map((t, j) => j === ti ? { ...t, [key]: val } : t) } : p));
  };
  const addTask = (pi) => {
    setPhases(prev => prev.map((p, i) => i === pi ? { ...p, tasks: [...p.tasks, { id: Date.now(), task: "", owner: "", startDate: "", endDate: "", duration: "", status: "Not Started", notes: "", milestone: false, blockedBy: "" }] } : p));
  };

  const isClient = (owner) => {
    const o = (owner || "").toLowerCase();
    return o.includes("client") || o === "[client]" || o === "[client / legal]";
  };

  /* Auto-cascade: set project start and calculate all dates from durations */
  const autoCascade = () => {
    const startStr = project.startDate;
    const parseD = (s) => { if (!s || s.startsWith("[")) return null; const p = s.split("/"); if (p.length >= 2) { const y = p[2] ? (parseInt(p[2]) < 100 ? 2000 + parseInt(p[2]) : parseInt(p[2])) : new Date().getFullYear(); return new Date(y, parseInt(p[1]) - 1, parseInt(p[0])); } return null; };
    const fmtD = (d) => `${String(d.getDate()).padStart(2,"0")}/${String(d.getMonth()+1).padStart(2,"0")}/${String(d.getFullYear()).slice(-2)}`;
    let cursor = parseD(startStr);
    if (!cursor) { showAlert("Set a valid project start date first (DD/MM or DD/MM/YY)"); return; }
    const updated = phases.map(phase => ({
      ...phase,
      tasks: phase.tasks.map(task => {
        const durMatch = (task.duration || "").match(/(\d+)/);
        const days = durMatch ? parseInt(durMatch[1]) : 1;
        const start = new Date(cursor);
        const end = new Date(cursor);
        end.setDate(end.getDate() + days - 1);
        cursor = new Date(end);
        cursor.setDate(cursor.getDate() + 1);
        /* Skip weekends for next task start */
        while (cursor.getDay() === 0 || cursor.getDay() === 6) cursor.setDate(cursor.getDate() + 1);
        return { ...task, startDate: fmtD(start), endDate: fmtD(end) };
      })
    }));
    setPhases(updated);
  };
  const deleteTask = (pi, ti) => {
    setPhases(prev => prev.map((p, i) => i === pi ? { ...p, tasks: p.tasks.filter((_, j) => j !== ti) } : p));
  };
  const toggleCollapse = (pi) => {
    setPhases(prev => prev.map((p, i) => i === pi ? { ...p, collapsed: !p.collapsed } : p));
  };
  const deletePhase = (pi) => {
    setPhases(prev => prev.filter((_, i) => i !== pi));
  };
  const editPhaseName = async (pi) => {
    const val = await showPrompt("Phase name:", phases[pi].name);
    if (val) setPhases(prev => prev.map((p, i) => i === pi ? { ...p, name: val.toUpperCase() } : p));
  };
  const addPhase = (name) => {
    setPhases(prev => [...prev, { id: Date.now(), name: name || "NEW PHASE", collapsed: false, tasks: [{ id: Date.now() + 1, task: "", owner: "", startDate: "", endDate: "", duration: "", status: "Not Started", notes: "" }] }]);
    setShowAddPhase(false);
  };
  const addCustomPhase = async () => {
    const name = await showPrompt("Phase name:");
    if (name) addPhase(name.toUpperCase());
  };

  /* Clone + sanitise: strips extension junk from a DOM clone */
  const cleanClone = (el) => {
    const clone = el.cloneNode(true);
    clone.querySelectorAll('[class*="lusha"],[id*="lusha"],[class*="Lusha"],[id*="Lusha"],[data-lusha],[class*="chrome-extension"],[id*="chrome-extension"],[class*="grammarly"],[id*="grammarly"],[class*="lastpass"],[id*="lastpass"],[class*="honey"],[id*="honey"],[class*="extension"]').forEach(n=>n.remove());
    clone.querySelectorAll('iframe,object,embed').forEach(n=>n.remove());
    return clone;
  };
  /* Collect @font-face rules for SackersGothic etc */
  const collectFontRules = () => { let r=""; try{for(const s of document.styleSheets){try{for(const ru of s.cssRules){if(ru.cssText&&ru.cssText.startsWith("@font-face"))r+=ru.cssText+"\n";}}catch(e){}}}catch(e){} return r; };
  /* Print via hidden iframe (immune to extensions) */
  const printViaIframe = (clone) => {
    const fontRules = collectFontRules();
    const iframe = document.createElement("iframe");
    iframe.style.cssText = "position:fixed;top:0;left:0;width:1200px;height:100%;border:none;z-index:-9999;opacity:0;";
    document.body.appendChild(iframe);
    const idoc = iframe.contentDocument;
    idoc.open();
    idoc.write(`<!DOCTYPE html><html><head><meta charset="UTF-8"><base href="${window.location.origin}/"><title>Production Schedule | ${project?.name||""}</title><style>
@import url('https://fonts.googleapis.com/css2?family=Nunito+Sans:wght@400;500;700&display=swap');
${fontRules}
*{box-sizing:border-box;margin:0;padding:0;-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important;color-adjust:exact!important}
body{background:#fff;font-family:'Avenir','Avenir Next','Nunito Sans',sans-serif;font-size:10px;color:#1a1a1a;padding:10mm 12mm;}
.page-break{page-break-before:always}
@media print{@page{size:landscape;margin:0}}
${PRINT_CLEANUP_CSS}
</style></head><body></body></html>`);
    idoc.close();
    idoc.body.appendChild(idoc.adoptNode(clone));
    const _imgs=[...idoc.querySelectorAll('img')];const _imgReady=_imgs.map(im=>im.complete?Promise.resolve():new Promise(r=>{im.onload=r;im.onerror=r;}));
    Promise.all(_imgReady).then(()=>{setTimeout(() => { const _t=document.title;document.title=`Production Schedule | ${project?.name||""}`; iframe.contentWindow.focus(); iframe.contentWindow.print(); window.addEventListener("afterprint",function _r(){document.title=_t;window.removeEventListener("afterprint",_r);},{ once:true }); setTimeout(()=>{document.title=_t;},5000); }, 300);});
  };
  const exportPDF = () => {
    const el = printRef.current; if (!el) return;
    printViaIframe(cleanClone(el));
  };
  const exportAllPDF = () => {
    setPrintTabs(new Set(["schedule","timeline","calendar"]));
    setTimeout(() => {
      const el = printRef.current; if (!el) { setPrintTabs(null); return; }
      printViaIframe(cleanClone(el));
      setTimeout(() => setPrintTabs(null), 100);
    }, 200);
  };
  /* Share: capture rendered HTML, POST to /api/cps-share, returns a live URL */
  const generateSharePage = async (modes, existingToken, existingResourceId) => {
    const captureHtml = () => {
      const el = printRef.current; if (!el) return null;
      const clone = cleanClone(el);
      clone.querySelectorAll('input').forEach(n => { const sp = document.createElement('span'); sp.textContent = n.value; sp.style.cssText = n.style.cssText; n.replaceWith(sp); });
      clone.querySelectorAll('img').forEach(im => { if(im.src && !im.src.startsWith('data:') && !im.src.startsWith('http')) im.src = window.location.origin + im.getAttribute('src'); });
      return clone.innerHTML;
    };
    const tabsArr = Array.isArray(modes) ? modes : (modes === "all" ? ["schedule","timeline","calendar"] : [modes]);
    setPrintTabs(new Set(tabsArr));
    await new Promise(r => setTimeout(r, 300));
    const html = captureHtml();
    setPrintTabs(null);
    if (!html) return;
    try {
      const body = { html, projectName: project.name || "", clientName: project.client || "", mode: tabsArr.join("+") };
      if (existingToken) body.token = existingToken;
      if (existingResourceId) body.resourceId = existingResourceId;
      const resp = await fetch("/api/cps-share", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) });
      const data = await resp.json();
      if (data.url) {
        if (onShareUrl) onShareUrl(data.url, data.token, data.id);
        else { await navigator.clipboard.writeText(data.url).catch(() => {}); showAlert("Link copied to clipboard!\n\n" + data.url); }
      } else { showAlert("Failed to generate link: " + (data.error || "Unknown error")); }
    } catch (err) { showAlert("Error generating link: " + err.message); }
  };

  useImperativeHandle(fwdRef, () => ({ share: generateSharePage }));

  /* Stats */
  const allTasks = phases.flatMap(p => p.tasks);
  const totalTasks = allTasks.length;
  const complete = allTasks.filter(t => t.status === "Complete").length;
  const inProgress = allTasks.filter(t => t.status === "In Progress").length;
  const blocked = allTasks.filter(t => t.status === "Blocked").length;
  const pctComplete = totalTasks > 0 ? Math.round((complete / totalTasks) * 100) : 0;

  /* Client actions */
  const clientActions = allTasks.filter(t => isClient(t.owner) && t.status !== "Complete" && t.status !== "Approved");
  const nextClientAction = clientActions.find(t => t.status === "In Progress" || t.status === "In Review") || clientActions[0];

  /* Current phase = first phase with incomplete tasks */
  const currentPhase = phases.find(p => p.tasks.some(t => t.status !== "Complete")) || phases[phases.length - 1];
  const milestones = allTasks.filter(t => t.milestone);

  return (
    <div style={{ width: _fitMobile ? "100%" : 1123, minWidth: _fitMobile ? 0 : 1123, margin: "0 auto", background: "#fff", fontFamily: CPS_F, color: "#1a1a1a" }}>
      {/* Top bar */}
      <div style={{ display: "flex", borderBottom: "2px solid #000", overflowX: "auto" }}>
        {[{ id: "schedule", label: "SCHEDULE" }, { id: "timeline", label: "TIMELINE" }, { id: "calendar", label: "CALENDAR" }].map(t => (
          <div key={t.id} onClick={() => setTab(t.id)} style={{ fontFamily: CPS_F, fontSize: 9, fontWeight: tab === t.id ? 700 : 400, letterSpacing: CPS_LS, padding: _fitMobile ? "8px 10px" : "10px 16px", cursor: "pointer", whiteSpace: "nowrap", flexShrink: 0, background: tab === t.id ? "#000" : "#f5f5f5", color: tab === t.id ? "#fff" : "#666", textTransform: "uppercase", borderRight: "1px solid #ddd" }}>
            {t.label}
          </div>
        ))}
        <div style={{ flex: 1 }} />
        <div onClick={autoCascade} style={{ fontFamily: CPS_F, fontSize: 9, fontWeight: 700, letterSpacing: CPS_LS, padding: "10px 16px", cursor: "pointer", whiteSpace: "nowrap", flexShrink: 0, background: "#f5f5f5", color: "#666", textTransform: "uppercase", borderLeft: "1px solid #ddd" }}
          onMouseEnter={e => e.currentTarget.style.background = "#eee"} onMouseLeave={e => e.currentTarget.style.background = "#f5f5f5"}>
          AUTO-DATE
        </div>
        
        <div onClick={exportPDF} style={{ fontFamily: CPS_F, fontSize: 9, fontWeight: 700, letterSpacing: CPS_LS, padding: "10px 16px", cursor: "pointer", background: "#333", color: "#fff", textTransform: "uppercase", borderLeft: "1px solid #555" }}
          onMouseEnter={e => e.target.style.background = "#555"} onMouseLeave={e => e.target.style.background = "#333"}>
          EXPORT PAGE
        </div>
        <div onClick={exportAllPDF} style={{ fontFamily: CPS_F, fontSize: 9, fontWeight: 700, letterSpacing: CPS_LS, padding: "10px 16px", cursor: "pointer", background: "#000", color: "#fff", textTransform: "uppercase", borderLeft: "1px solid #333" }}
          onMouseEnter={e => e.target.style.background = "#333"} onMouseLeave={e => e.target.style.background = "#000"}>
          EXPORT ALL
        </div>
      </div>

      <div ref={printRef} style={{ padding: "20px 12px" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 4, flexWrap: _fitMobile ? "wrap" : "nowrap", gap: _fitMobile ? 8 : 0 }}><img src="/onna-default-logo.png" alt="ONNA" style={{ maxHeight: 30, maxWidth: 120, objectFit: "contain" }} /></div>
        <div style={{ borderBottom: "2.5px solid #000", marginBottom: 16 }} />

        <div style={{ textAlign: "center", fontFamily: CPS_F, fontSize: 12, fontWeight: 700, letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 8 }}>
          CREATIVE PRODUCTION SCHEDULE
        </div>

        {/* Project info */}
        <div style={{ display: "flex", gap: 4, marginBottom: 12, flexWrap: "wrap" }}>
          {[["PROJECT:", project.name, "name"], ["CLIENT:", project.client, "client"], ["START:", project.startDate, "startDate"], ["DELIVERY:", project.deliveryDate, "deliveryDate"], ["PRODUCER:", project.producer, "producer"]].map(([lbl, val, key]) => (
            <div key={key} style={{ display: "flex", gap: 4, alignItems: "baseline", flex: 1, minWidth: _fitMobile ? "45%" : "auto", marginRight: 16 }}>
              <span style={{ fontFamily: CPS_F, fontSize: 9, fontWeight: 700, letterSpacing: CPS_LS }}>{lbl}</span>
              <CpsCell value={val} onChange={v => setProject(p => ({ ...p, [key]: v }))} />
            </div>
          ))}
        </div>

        {/* Status summary banner */}
        <div style={{ display: "flex", gap: 8, marginBottom: 14, alignItems: "stretch", flexWrap: _fitMobile ? "wrap" : "nowrap" }}>
          <div style={{ flex: 1, minWidth: _fitMobile ? "45%" : "auto", background: currentPhase ? (CPS_PHASE_COLORS[currentPhase.name] || "#1a1a1a") : "#1a1a1a", padding: "8px 12px", borderRadius: 2 }}>
            <div style={{ fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: "rgba(255,255,255,0.6)", textTransform: "uppercase", marginBottom: 2 }}>CURRENT PHASE</div>
            <div style={{ fontFamily: CPS_F, fontSize: 12, fontWeight: 700, letterSpacing: CPS_LS, color: "#fff" }}>{currentPhase ? currentPhase.name : "\u2014"}</div>
          </div>
          <div style={{ flex: 1, minWidth: _fitMobile ? "45%" : "auto", background: nextClientAction ? "#FFE082" : "#E8F5E9", padding: "8px 12px", borderRadius: 2, border: nextClientAction ? "1px solid #FFD54F" : "1px solid #A5D6A7" }}>
            <div style={{ fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: nextClientAction ? "#000" : "#2E7D32", textTransform: "uppercase", marginBottom: 2 }}>
              {nextClientAction ? "NEXT CLIENT ACTION" : "NO CLIENT ACTIONS PENDING"}
            </div>
            <div style={{ fontFamily: CPS_F, fontSize: 10, fontWeight: 700, letterSpacing: CPS_LS, color: nextClientAction ? "#000" : "#2E7D32" }}>
              {nextClientAction ? nextClientAction.task : "All clear"}
            </div>
            {nextClientAction && nextClientAction.endDate && (
              <div style={{ fontFamily: CPS_F, fontSize: 7, letterSpacing: CPS_LS, color: "#000", marginTop: 1 }}>Due: {nextClientAction.endDate}</div>
            )}
          </div>
          <div style={{ background: "#f4f4f4", padding: "8px 12px", borderRadius: 2, minWidth: 80, textAlign: "center" }}>
            <div style={{ fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: "#999", textTransform: "uppercase", marginBottom: 2 }}>PROGRESS</div>
            <div style={{ fontFamily: CPS_F, fontSize: 16, fontWeight: 700, letterSpacing: CPS_LS, color: "#000" }}>{pctComplete}%</div>
            <div style={{ height: 3, background: "#ddd", borderRadius: 2, marginTop: 4 }}>
              <div style={{ height: 3, background: "#000", borderRadius: 2, width: `${pctComplete}%` }} />
            </div>
          </div>
          <div style={{ background: clientActions.length > 0 ? "#FFE082" : "#f4f4f4", padding: "8px 12px", borderRadius: 2, minWidth: 60, textAlign: "center" }}>
            <div style={{ fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: clientActions.length > 0 ? "#000" : "#999", textTransform: "uppercase", marginBottom: 2 }}>CLIENT</div>
            <div style={{ fontFamily: CPS_F, fontSize: 16, fontWeight: 700, letterSpacing: CPS_LS, color: clientActions.length > 0 ? "#000" : "#999" }}>{clientActions.length}</div>
          </div>
          <div style={{ background: blocked > 0 ? "#FCE4EC" : "#f4f4f4", padding: "8px 12px", borderRadius: 2, minWidth: 60, textAlign: "center" }}>
            <div style={{ fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: blocked > 0 ? "#C62828" : "#999", textTransform: "uppercase", marginBottom: 2 }}>BLOCKED</div>
            <div style={{ fontFamily: CPS_F, fontSize: 16, fontWeight: 700, letterSpacing: CPS_LS, color: blocked > 0 ? "#C62828" : "#999" }}>{blocked}</div>
          </div>
        </div>

        {/* \u2550\u2550\u2550 SCHEDULE TAB \u2550\u2550\u2550 */}
        {(tab === "schedule" || (printTabs && printTabs.has("schedule"))) && <>
        {/* Progress bar */}
        <div style={{ marginBottom: 14 }}>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 3 }}>
            <span style={{ fontFamily: CPS_F, fontSize: 8, fontWeight: 700, letterSpacing: CPS_LS, color: "#999" }}>OVERALL PROGRESS</span>
            <span style={{ fontFamily: CPS_F, fontSize: 8, fontWeight: 700, letterSpacing: CPS_LS, color: "#000" }}>{pctComplete}% ({complete}/{totalTasks})</span>
          </div>
          <div style={{ height: 6, background: "#f0f0f0", borderRadius: 3 }}>
            <div style={{ height: 6, background: "#000", borderRadius: 3, width: `${pctComplete}%`, transition: "width .3s" }} />
          </div>
          <div style={{ display: "flex", gap: 10, marginTop: 6 }}>
            {[
              { label: "In Progress", count: inProgress, color: "#E65100" },
              { label: "Blocked", count: blocked, color: "#C62828" },
              { label: "Complete", count: complete, color: "#000" },
            ].map(s => (
              <span key={s.label} style={{ fontFamily: CPS_F, fontSize: 7, letterSpacing: CPS_LS, color: s.color, fontWeight: 700 }}>{s.label.toUpperCase()}: {s.count}</span>
            ))}
          </div>
        </div>

        {/* Phases */}
        {phases.map((phase, pi) => {
          const phaseColor = CPS_PHASE_COLORS[phase.name] || "#1a1a1a";
          const phaseComplete = phase.tasks.filter(t => t.status === "Complete").length;
          const phaseTotal = phase.tasks.length;
          const phasePct = phaseTotal > 0 ? Math.round((phaseComplete / phaseTotal) * 100) : 0;

          return (
            <div key={phase.id} style={{ marginBottom: 12 }}>
              {/* Phase header */}
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", background: phaseColor, padding: "5px 8px", cursor: "pointer" }}
                onClick={() => toggleCollapse(pi)}>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <span style={{ fontFamily: CPS_F, fontSize: 8, color: "rgba(255,255,255,0.6)", transform: phase.collapsed ? "rotate(0deg)" : "rotate(90deg)", transition: "transform .15s", display: "inline-block" }}>▶</span>
                  <span onClick={e => { e.stopPropagation(); editPhaseName(pi); }} style={{ fontFamily: CPS_F, fontSize: 10, fontWeight: 700, letterSpacing: CPS_LS, color: "#fff", textTransform: "uppercase", cursor: "pointer" }}>{phase.name}</span>
                  <span style={{ fontFamily: CPS_F, fontSize: 8, color: "rgba(255,255,255,0.5)", letterSpacing: CPS_LS }}>{phasePct}% ({phaseComplete}/{phaseTotal})</span>
                </div>
                <div style={{ display: "flex", gap: 10, alignItems: "center" }} onClick={e => e.stopPropagation()}>
                  <span onClick={() => addTask(pi)} style={{ fontFamily: CPS_F, fontSize: 8, color: "rgba(255,255,255,0.55)", cursor: "pointer", letterSpacing: CPS_LS }}
                    onMouseEnter={e => e.target.style.color = "#fff"} onMouseLeave={e => e.target.style.color = "rgba(255,255,255,0.55)"}>
                    + ADD TASK
                  </span>
                  <span onClick={() => deletePhase(pi)} style={{ fontFamily: CPS_F, fontSize: 10, color: "rgba(255,255,255,0.3)", cursor: "pointer" }}
                    onMouseEnter={e => e.target.style.color = "#e53935"} onMouseLeave={e => e.target.style.color = "rgba(255,255,255,0.3)"}>
                    ×
                  </span>
                </div>
              </div>

              {/* Phase progress mini-bar */}
              {!phase.collapsed && (
                <div style={{ height: 2, background: "#f0f0f0" }}>
                  <div style={{ height: 2, background: phaseColor, width: `${phasePct}%`, transition: "width .3s", opacity: 0.6 }} />
                </div>
              )}

              {/* Column headers */}
              {!phase.collapsed && (
                <div style={{ overflowX: "auto" }}>
                  <div style={{ display: "flex", background: "#f4f4f4", borderBottom: "1px solid #ddd", minWidth: _fitMobile ? 700 : 0 }}>
                    <div style={{ width: 24, fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: "#999", padding: "4px 4px", textAlign: "center" }}>#</div>
                    <div style={{ width: 18 }} />
                    <div style={{ flex: 2, fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: "#999", padding: "4px 6px" }}>TASK</div>
                    <div style={{ flex: 0.8, fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: "#999", padding: "4px 6px" }}>OWNER</div>
                    <div style={{ flex: 0.6, fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: "#999", padding: "4px 6px" }}>START</div>
                    <div style={{ flex: 0.6, fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: "#999", padding: "4px 6px" }}>END</div>
                    <div style={{ flex: 0.5, fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: "#999", padding: "4px 6px" }}>DURATION</div>
                    <div style={{ flex: 0.6, fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: "#999", padding: "4px 6px" }}>STATUS</div>
                    <div style={{ flex: 1, fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: "#999", padding: "4px 6px" }}>NOTES</div>
                  </div>

                  {/* Tasks */}
                  {phase.tasks.map((task, ti) => {
                    const clientTask = isClient(task.owner);
                    const isComplete = task.status === "Complete";
                    return (
                    <div key={task.id} style={{ display: "flex", borderBottom: "1px solid #f0f0f0", alignItems: "center", minHeight: 28, minWidth: _fitMobile ? 700 : 0, borderLeft: `3px solid ${clientTask && !isComplete ? "#FFD54F" : phaseColor + "20"}`, background: clientTask && !isComplete ? "#FFE082" : "transparent" }}>
                      <div style={{ width: 24, fontFamily: CPS_F, fontSize: 8, fontWeight: 700, color: "#ccc", padding: "3px 4px", textAlign: "center" }}>
                        {task.milestone ? <span style={{ color: phaseColor, fontSize: 9 }}>{"\u25C6"}</span> : (ti + 1)}
                      </div>
                      <div style={{ width: 18, display: "flex", alignItems: "center", justifyContent: "center" }}>
                        <span onClick={() => deleteTask(pi, ti)} style={{ cursor: "pointer", fontSize: 10, color: "#ddd" }}
                          onMouseEnter={e => e.target.style.color = "#e53935"} onMouseLeave={e => e.target.style.color = "#ddd"}>{"\u00d7"}</span>
                      </div>
                      <div style={{ flex: 2, display: "flex", alignItems: "center", gap: 4 }}>
                        <CpsCell value={task.task} onChange={v => updateTask(pi, ti, "task", v)} style={{ fontWeight: isComplete ? 400 : task.milestone ? 700 : 500, textDecoration: isComplete ? "line-through" : "none", color: isComplete ? "#999" : "#1a1a1a", flex: 1 }} placeholder="Task description" />
                        {task.blockedBy && <span style={{ fontFamily: CPS_F, fontSize: 6, letterSpacing: CPS_LS, color: "#C62828", background: "#FCE4EC", padding: "1px 4px", borderRadius: 2, whiteSpace: "nowrap", flexShrink: 0 }}>{"\u26D4"} {task.blockedBy}</span>}
                      </div>
                      <div style={{ flex: 0.8 }}>
                        <CpsCell value={task.owner} onChange={v => updateTask(pi, ti, "owner", v)} style={{ color: clientTask ? "#000" : "#666", fontWeight: clientTask ? 700 : 400 }} placeholder="Owner" />
                      </div>
                      <div style={{ flex: 0.6 }}>
                        <CpsCell value={task.startDate} onChange={v => updateTask(pi, ti, "startDate", v)} placeholder="DD/MM" />
                      </div>
                      <div style={{ flex: 0.6 }}>
                        <CpsCell value={task.endDate} onChange={v => updateTask(pi, ti, "endDate", v)} placeholder="DD/MM" />
                      </div>
                      <div style={{ flex: 0.5 }}>
                        <CpsCell value={task.duration} onChange={v => updateTask(pi, ti, "duration", v)} style={{ color: "#999" }} placeholder="e.g. 3 days" />
                      </div>
                      <div style={{ flex: 0.6, padding: "2px 4px" }}>
                        <CpsStatusBadge value={task.status} onChange={v => updateTask(pi, ti, "status", v)} />
                      </div>
                      <div style={{ flex: 1 }}>
                        <CpsCell value={task.notes} onChange={v => updateTask(pi, ti, "notes", v)} style={{ color: "#999", fontStyle: task.notes ? "italic" : "normal" }} placeholder="Notes" />
                      </div>
                    </div>
                    );
                  })}
                  {phase.tasks.length === 0 && (
                    <div style={{ fontFamily: CPS_F, fontSize: 9, color: "#ccc", letterSpacing: CPS_LS, padding: "12px 42px", fontStyle: "italic" }}>
                      No tasks — click + ADD TASK
                    </div>
                  )}
                </div>
              )}
            </div>
          );
        })}

        {/* + ADD PHASE inline */}
        <div style={{ position: "relative", marginBottom: 16 }}>
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", background: showAddPhase ? "#333" : "#f4f4f4", padding: "6px 8px", cursor: "pointer", borderRadius: 1, transition: "background .15s" }}
            onClick={() => setShowAddPhase(!showAddPhase)}
            onMouseEnter={e => { if (!showAddPhase) e.currentTarget.style.background = "#eee"; }}
            onMouseLeave={e => { if (!showAddPhase) e.currentTarget.style.background = "#f4f4f4"; }}>
            <span style={{ fontFamily: CPS_F, fontSize: 9, fontWeight: 700, letterSpacing: CPS_LS, color: showAddPhase ? "#fff" : "#999", textTransform: "uppercase" }}>+ ADD PHASE</span>
          </div>
          {showAddPhase && (
            <div style={{ background: "#fff", border: "1px solid #ddd", borderTop: "none", boxShadow: "0 4px 12px rgba(0,0,0,0.08)" }}>
              {Object.keys(CPS_PHASE_COLORS).map(name => (
                <div key={name} onClick={() => { addPhase(name); }}
                  style={{ fontFamily: CPS_F, fontSize: 9, letterSpacing: CPS_LS, padding: "8px 12px", cursor: "pointer", borderBottom: "1px solid #f0f0f0", color: "#666", display: "flex", alignItems: "center", gap: 8 }}
                  onMouseEnter={e => e.currentTarget.style.background = "#f5f5f5"} onMouseLeave={e => e.currentTarget.style.background = "#fff"}>
                  <span style={{ width: 10, height: 10, borderRadius: 2, background: CPS_PHASE_COLORS[name], flexShrink: 0 }} />
                  {name}
                </div>
              ))}
              <div onClick={addCustomPhase}
                style={{ fontFamily: CPS_F, fontSize: 9, letterSpacing: CPS_LS, padding: "8px 12px", cursor: "pointer", color: "#999", fontStyle: "italic" }}
                onMouseEnter={e => e.currentTarget.style.background = "#f5f5f5"} onMouseLeave={e => e.currentTarget.style.background = "#fff"}>
                Custom Phase...
              </div>
            </div>
          )}
        </div>

        </>}

        {/* ═══ TIMELINE TAB ═══ */}
        {(printTabs && printTabs.has("timeline") && printTabs.has("schedule")) && <div className="page-break" style={{pageBreakBefore:"always",marginTop:32,paddingTop:16,borderTop:"2px solid #000"}}><span style={{fontFamily:CPS_F,fontSize:11,fontWeight:700,letterSpacing:1.5,textTransform:"uppercase"}}>TIMELINE</span></div>}
        {(tab === "timeline" || (printTabs && printTabs.has("timeline"))) && (() => {
          /* Parse dates from tasks to build timeline */
          const parseDate = (str) => {
            if (!str || str.startsWith("[")) return null;
            const parts = str.split("/");
            if (parts.length === 2) {
              const d = parseInt(parts[0]), m = parseInt(parts[1]) - 1;
              const y = new Date().getFullYear();
              return new Date(y, m, d);
            }
            if (parts.length === 3) {
              const d = parseInt(parts[0]), m = parseInt(parts[1]) - 1, y = parseInt(parts[2]);
              return new Date(y < 100 ? 2000 + y : y, m, d);
            }
            const parsed = new Date(str);
            return isNaN(parsed) ? null : parsed;
          };

          /* Collect all dates to find range */
          let minDate = null, maxDate = null;
          phases.forEach(phase => {
            phase.tasks.forEach(task => {
              const s = parseDate(task.startDate);
              const e = parseDate(task.endDate);
              if (s) { if (!minDate || s < minDate) minDate = s; if (!maxDate || s > maxDate) maxDate = s; }
              if (e) { if (!minDate || e < minDate) minDate = e; if (!maxDate || e > maxDate) maxDate = e; }
            });
          });

          /* Default to 12 weeks if no dates entered */
          if (!minDate) minDate = new Date();
          if (!maxDate || maxDate <= minDate) maxDate = new Date(minDate.getTime() + 84 * 86400000);

          /* Pad by 1 week each side */
          const timeStart = new Date(minDate.getTime() - 7 * 86400000);
          const timeEnd = new Date(maxDate.getTime() + 7 * 86400000);
          const totalDays = Math.ceil((timeEnd - timeStart) / 86400000);

          /* Build week markers */
          const weeks = [];
          const ws = new Date(timeStart);
          ws.setDate(ws.getDate() - ws.getDay() + 1); /* Monday */
          while (ws < timeEnd) {
            weeks.push(new Date(ws));
            ws.setDate(ws.getDate() + 7);
          }

          const dayToX = (date) => {
            if (!date) return 0;
            const diff = (date - timeStart) / 86400000;
            return (diff / totalDays) * 100;
          };

          const LABEL_W = _fitMobile ? 120 : 220;
          const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

          /* Today marker */
          const today = new Date();
          const todayX = dayToX(today);

          return (
            <div>
              {/* Timeline header with weeks */}
              <div style={{ display: "flex", marginBottom: 0 }}>
                <div style={{ width: LABEL_W, flexShrink: 0 }} />
                <div style={{ flex: 1, position: "relative", height: 28, borderBottom: "1px solid #ddd" }}>
                  {weeks.map((w, i) => {
                    const x = dayToX(w);
                    return (
                      <div key={i} style={{ position: "absolute", left: `${x}%`, top: 0, height: "100%", borderLeft: "1px solid #eee" }}>
                        <span style={{ fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: "#999", position: "absolute", top: 2, left: 3, whiteSpace: "nowrap" }}>
                          {w.getDate()} {months[w.getMonth()]}
                        </span>
                      </div>
                    );
                  })}
                  {/* Today label */}
                  {todayX >= 0 && todayX <= 100 && (
                    <div style={{ position: "absolute", left: `${todayX}%`, top: 0, height: "100%", width: 1.5, background: "#e53935", zIndex: 5, opacity: 0.7 }}>
                      <span style={{ fontFamily: CPS_F, fontSize: 6, fontWeight: 700, color: "#e53935", position: "absolute", top: -10, left: 3, whiteSpace: "nowrap" }}>TODAY</span>
                    </div>
                  )}
                </div>
              </div>

              {/* Phases and tasks */}
              {phases.map((phase, pi) => {
                const phaseColor = CPS_PHASE_COLORS[phase.name] || "#1a1a1a";

                /* Calculate phase span */
                let phaseStart = null, phaseEnd = null;
                phase.tasks.forEach(t => {
                  const s = parseDate(t.startDate), e = parseDate(t.endDate);
                  if (s) { if (!phaseStart || s < phaseStart) phaseStart = s; }
                  if (e) { if (!phaseEnd || e > phaseEnd) phaseEnd = e; }
                  if (s && !e) { if (!phaseEnd || s > phaseEnd) phaseEnd = s; }
                });

                return (
                  <div key={phase.id} style={{ marginBottom: 2 }}>
                    {/* Phase bar */}
                    <div style={{ display: "flex", alignItems: "center", minHeight: 22, background: "#fafafa" }}>
                      <div style={{ width: LABEL_W, flexShrink: 0, fontFamily: CPS_F, fontSize: 8, fontWeight: 700, letterSpacing: CPS_LS, color: phaseColor, padding: "3px 8px", textTransform: "uppercase" }}>
                        {phase.name}
                      </div>
                      <div style={{ flex: 1, position: "relative", height: 16 }}>
                        {todayX >= 0 && todayX <= 100 && <div style={{ position: "absolute", left: `${todayX}%`, top: 0, height: "100%", width: 1.5, background: "#e53935", opacity: 0.3, zIndex: 2 }} />}
                        {phaseStart && phaseEnd && (
                          <div style={{
                            position: "absolute",
                            left: `${dayToX(phaseStart)}%`,
                            width: `${Math.max(dayToX(phaseEnd) - dayToX(phaseStart), 0.5)}%`,
                            height: 12, top: 2,
                            background: phaseColor, opacity: 0.15, borderRadius: 2,
                          }} />
                        )}
                      </div>
                    </div>

                    {/* Task bars */}
                    {phase.tasks.map((task, ti) => {
                      const s = parseDate(task.startDate);
                      const e = parseDate(task.endDate);
                      const hasBar = s && e;
                      const isComplete = task.status === "Complete";
                      const isBlocked = task.status === "Blocked";
                      const clientTask = isClient(task.owner);

                      return (
                        <div key={task.id} style={{ display: "flex", alignItems: "center", minHeight: 20, borderBottom: "1px solid #f5f5f5", background: clientTask && !isComplete ? "#FFE08240" : "transparent" }}>
                          <div style={{ width: LABEL_W, flexShrink: 0, fontFamily: CPS_F, fontSize: 8, letterSpacing: CPS_LS, color: clientTask && !isComplete ? "#000" : isComplete ? "#ccc" : "#666", padding: "2px 8px 2px 16px", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", textDecoration: isComplete ? "line-through" : "none", display: "flex", alignItems: "center", gap: 4 }}>
                            {task.milestone && <span style={{ color: phaseColor, fontSize: 7, flexShrink: 0 }}>{"\u25C6"}</span>}
                            {clientTask && !isComplete && <span style={{ fontSize: 7, flexShrink: 0 }}>{"\u26A0"}</span>}
                            <span style={{ overflow: "hidden", textOverflow: "ellipsis" }}>{task.task || "\u2014"}</span>
                          </div>
                          <div style={{ flex: 1, position: "relative", height: 16 }}>
                            {weeks.map((w, i) => (
                              <div key={i} style={{ position: "absolute", left: `${dayToX(w)}%`, top: 0, height: "100%", borderLeft: "1px solid #f5f5f5" }} />
                            ))}
                            {todayX >= 0 && todayX <= 100 && <div style={{ position: "absolute", left: `${todayX}%`, top: 0, height: "100%", width: 1.5, background: "#e53935", opacity: 0.3, zIndex: 2 }} />}
                            {hasBar && task.milestone && (
                              <div style={{ position: "absolute", left: `${dayToX(s)}%`, top: 1, fontSize: 12, color: phaseColor, transform: "translateX(-50%)", zIndex: 3 }}>{"\u25C6"}</div>
                            )}
                            {hasBar && !task.milestone && (
                              <div style={{
                                position: "absolute",
                                left: `${dayToX(s)}%`,
                                width: `${Math.max(dayToX(e) - dayToX(s), 0.3)}%`,
                                height: 10, top: 3,
                                background: clientTask && !isComplete ? "#FFD54F" : isBlocked ? "#e53935" : isComplete ? "#ccc" : phaseColor,
                                borderRadius: 2,
                                opacity: isComplete ? 0.4 : 0.85,
                                border: clientTask && !isComplete ? "1px solid #F9A825" : "none",
                              }} />
                            )}
                            {!hasBar && (
                              <div style={{ fontFamily: CPS_F, fontSize: 7, color: "#ddd", padding: "3px 4px", letterSpacing: CPS_LS }}>
                                Enter start/end dates in Schedule tab
                              </div>
                            )}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                );
              })}

              {/* Legend */}
              <div style={{ display: "flex", gap: 12, marginTop: 16, flexWrap: "wrap" }}>
                {phases.map(p => (
                  <div key={p.id} style={{ display: "flex", alignItems: "center", gap: 4 }}>
                    <span style={{ width: 10, height: 10, borderRadius: 2, background: CPS_PHASE_COLORS[p.name] || "#1a1a1a", flexShrink: 0 }} />
                    <span style={{ fontFamily: CPS_F, fontSize: 7, letterSpacing: CPS_LS, color: "#666" }}>{p.name}</span>
                  </div>
                ))}
                <div style={{ display: "flex", alignItems: "center", gap: 4 }}>
                  <span style={{ width: 10, height: 1.5, background: "#e53935", flexShrink: 0 }} />
                  <span style={{ fontFamily: CPS_F, fontSize: 7, letterSpacing: CPS_LS, color: "#e53935" }}>TODAY</span>
                </div>
              </div>
            </div>
          );
        })()}

        {/* ═══ CALENDAR TAB ═══ */}
        {(printTabs && printTabs.has("calendar") && (printTabs.has("schedule") || printTabs.has("timeline"))) && <div className="page-break" style={{pageBreakBefore:"always",marginTop:32,paddingTop:16,borderTop:"2px solid #000"}}><span style={{fontFamily:CPS_F,fontSize:11,fontWeight:700,letterSpacing:1.5,textTransform:"uppercase"}}>CALENDAR</span></div>}
        {(tab === "calendar" || (printTabs && printTabs.has("calendar"))) && (() => {
          const parseDate = (str) => {
            if (!str || str.startsWith("[")) return null;
            const parts = str.split("/");
            if (parts.length === 2) { return new Date(new Date().getFullYear(), parseInt(parts[1]) - 1, parseInt(parts[0])); }
            if (parts.length === 3) { const y = parseInt(parts[2]); return new Date(y < 100 ? 2000 + y : y, parseInt(parts[1]) - 1, parseInt(parts[0])); }
            const p = new Date(str); return isNaN(p) ? null : p;
          };

          /* Find date range from all tasks */
          let minDate = null, maxDate = null;
          phases.forEach(phase => {
            phase.tasks.forEach(task => {
              const s = parseDate(task.startDate), e = parseDate(task.endDate);
              [s, e].forEach(d => { if (d) { if (!minDate || d < minDate) minDate = d; if (!maxDate || d > maxDate) maxDate = d; } });
            });
          });
          if (!minDate) minDate = new Date();
          if (!maxDate || maxDate <= minDate) maxDate = new Date(minDate.getTime() + 84 * 86400000);

          /* Build month/weeks to display */
          const startMonth = new Date(minDate.getFullYear(), minDate.getMonth(), 1);
          const endMonth = new Date(maxDate.getFullYear(), maxDate.getMonth() + 1, 0);
          const months = [];
          const cur = new Date(startMonth);
          while (cur <= endMonth) {
            months.push(new Date(cur));
            cur.setMonth(cur.getMonth() + 1);
          }

          const MONTH_NAMES = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
          const DAY_NAMES = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];
          const today = new Date();
          today.setHours(0, 0, 0, 0);

          /* Collect tasks per day */
          const tasksByDay = {};
          phases.forEach(phase => {
            const phaseColor = CPS_PHASE_COLORS[phase.name] || "#1a1a1a";
            phase.tasks.forEach(task => {
              const s = parseDate(task.startDate), e = parseDate(task.endDate);
              if (s && e) {
                const d = new Date(s);
                while (d <= e) {
                  const key = `${d.getFullYear()}-${d.getMonth()}-${d.getDate()}`;
                  if (!tasksByDay[key]) tasksByDay[key] = [];
                  tasksByDay[key].push({ task: task.task, status: task.status, color: phaseColor, phase: phase.name, isStart: d.getTime() === s.getTime(), isEnd: d.getTime() === e.getTime() });
                  d.setDate(d.getDate() + 1);
                }
              } else if (s) {
                const key = `${s.getFullYear()}-${s.getMonth()}-${s.getDate()}`;
                if (!tasksByDay[key]) tasksByDay[key] = [];
                tasksByDay[key].push({ task: task.task, status: task.status, color: phaseColor, phase: phase.name, isStart: true, isEnd: true });
              }
            });
          });

          return (
            <div>
              {months.map((month, mi) => {
                const year = month.getFullYear();
                const m = month.getMonth();
                const firstDay = new Date(year, m, 1);
                const lastDay = new Date(year, m + 1, 0);
                const startPad = (firstDay.getDay() + 6) % 7; /* Monday = 0 */
                const totalDays = lastDay.getDate();
                const cells = [];

                /* Pad start */
                for (let i = 0; i < startPad; i++) cells.push(null);
                for (let d = 1; d <= totalDays; d++) cells.push(d);
                /* Pad end to complete week */
                while (cells.length % 7 !== 0) cells.push(null);

                return (
                  <div key={mi} style={{ marginBottom: 20 }}>
                    <div style={{ fontFamily: CPS_F, fontSize: 11, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase", marginBottom: 6, color: "#1a1a1a" }}>
                      {MONTH_NAMES[m]} {year}
                    </div>
                    {/* Day headers */}
                    <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 1, marginBottom: 1 }}>
                      {DAY_NAMES.map(d => (
                        <div key={d} style={{ fontFamily: CPS_F, fontSize: 7, fontWeight: 700, letterSpacing: CPS_LS, color: "#999", padding: "3px 4px", textAlign: "center", textTransform: "uppercase" }}>{d}</div>
                      ))}
                    </div>
                    {/* Day cells */}
                    <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 1 }}>
                      {cells.map((day, ci) => {
                        if (day === null) return <div key={ci} style={{ minHeight: 60, background: "#fafafa" }} />;
                        const dateObj = new Date(year, m, day);
                        const key = `${year}-${m}-${day}`;
                        const tasks = tasksByDay[key] || [];
                        const isToday = dateObj.getTime() === today.getTime();
                        const isWeekend = ci % 7 >= 5;

                        return (
                          <div key={ci} style={{
                            minHeight: 60, background: isToday ? "#FFF8E1" : isWeekend ? "#fafafa" : "#fff",
                            border: isToday ? "2px solid #E65100" : "1px solid #f0f0f0",
                            padding: "2px 3px", overflow: "hidden",
                          }}>
                            <div style={{ fontFamily: CPS_F, fontSize: 8, fontWeight: isToday ? 700 : 600, color: isToday ? "#E65100" : "#666", marginBottom: 2 }}>{day}</div>
                            {tasks.slice(0, 4).map((t, ti) => (
                              <div key={ti} style={{
                                fontFamily: CPS_F, fontSize: 6, letterSpacing: 0.3,
                                background: t.status === "Complete" ? "#eee" : t.status === "Blocked" ? "#FCE4EC" : `${t.color}18`,
                                color: t.status === "Complete" ? "#999" : t.color,
                                padding: "1px 3px", marginBottom: 1, borderRadius: 1,
                                borderLeft: t.isStart ? `2px solid ${t.color}` : "none",
                                whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
                                textDecoration: t.status === "Complete" ? "line-through" : "none",
                                fontWeight: t.isStart ? 600 : 400,
                              }}>
                                {t.task}
                              </div>
                            ))}
                            {tasks.length > 4 && (
                              <div style={{ fontFamily: CPS_F, fontSize: 6, color: "#999" }}>+{tasks.length - 4} more</div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })}

              {/* Legend */}
              <div style={{ display: "flex", gap: 12, marginTop: 8, flexWrap: "wrap" }}>
                {phases.map(p => (
                  <div key={p.id} style={{ display: "flex", alignItems: "center", gap: 4 }}>
                    <span style={{ width: 10, height: 10, borderRadius: 2, background: CPS_PHASE_COLORS[p.name] || "#1a1a1a", flexShrink: 0 }} />
                    <span style={{ fontFamily: CPS_F, fontSize: 7, letterSpacing: CPS_LS, color: "#666" }}>{p.name}</span>
                  </div>
                ))}
              </div>
            </div>
          );
        })()}

        {/* Footer */}
        <div style={{ marginTop: 32, display: "flex", justifyContent: "space-between", fontFamily: CPS_F, fontSize: 9, letterSpacing: CPS_LS, color: "#000", borderTop: "2px solid #000", paddingTop: 12 }}>
          <div><div style={{ fontWeight: 700 }}>@ONNAPRODUCTION</div><div>DUBAI | LONDON</div></div>
          <div style={{ textAlign: "right" }}><div style={{ fontWeight: 700 }}>WWW.ONNA.WORLD</div><div>HELLO@ONNAPRODUCTION.COM</div></div>
        </div>
      </div>
    </div>
  );
});

// ─── CONNIE HELPERS ─────────────────────────────────────────────────────────

/* ======= SHOT LIST CONNIE ======= */

export default CPSPolly;
